class SensitiveDataRedactor {
  static const List<String> _sensitiveKeys = [
    'password',
    'passwd',
    'pass',
    'secret',
    'token',
    'access_token',
    'refresh_token',
    'id_token',
    'api_key',
    'apikey',
    'api_secret',
    'authorization',
    'auth',
    'cookie',
    'set-cookie',
    'x-api-key',
    'x-auth-token',
    'credit_card',
    'card_number',
    'cvv',
    'cvc',
    'ssn',
    'social_security',
    'pin',
    'otp',
    'totp',
    'private_key',
    'session_id',
    'sessionid',
    'csrf',
    'xsrf',
  ];

  static const List<RegExp> _sensitivePatterns = [];

  static final List<RegExp> _valuePatterns = [
    RegExp(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'), // email
    RegExp(r'\b\d{3}-\d{2}-\d{4}\b'), // SSN
    RegExp(r'\b\d{13,19}\b'), // credit card numbers
    RegExp(r'eyJ[A-Za-z0-9_-]+\.eyJ[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+'), // JWT
    RegExp(r'Bearer\s+[A-Za-z0-9._~+/=-]+'), // Bearer tokens
  ];

  static const String _redactedPlaceholder = '***REDACTED***';

  /// Redact sensitive data from a map (e.g., headers, body, query params)
  static Map<String, dynamic> redactMap(Map<String, dynamic>? input) {
    if (input == null) return {};
    final result = <String, dynamic>{};
    for (final entry in input.entries) {
      result[entry.key] = _redactValue(entry.key, entry.value);
    }
    return result;
  }

  /// Redact sensitive data from headers specifically
  static Map<String, String> redactHeaders(Map<String, String>? headers) {
    if (headers == null) return {};
    final result = <String, String>{};
    for (final entry in headers.entries) {
      if (_isSensitiveKey(entry.key)) {
        result[entry.key] = _redactedPlaceholder;
      } else {
        result[entry.key] = _redactStringValue(entry.value);
      }
    }
    return result;
  }

  /// Redact sensitive values from a string
  static String redactString(String? input) {
    if (input == null) return '';
    return _redactStringValue(input);
  }

  static dynamic _redactValue(String key, dynamic value) {
    if (_isSensitiveKey(key)) {
      return _redactedPlaceholder;
    }
    if (value is String) {
      return _redactStringValue(value);
    }
    if (value is Map<String, dynamic>) {
      return redactMap(value);
    }
    if (value is List) {
      return value.map((item) {
        if (item is Map<String, dynamic>) return redactMap(item);
        if (item is String) return _redactStringValue(item);
        return item;
      }).toList();
    }
    return value;
  }

  static bool _isSensitiveKey(String key) {
    final lowerKey = key.toLowerCase().replaceAll(RegExp(r'[-_\s]'), '');
    return _sensitiveKeys.any(
        (sensitive) => lowerKey.contains(sensitive.replaceAll(RegExp(r'[-_\s]'), '')));
  }

  static String _redactStringValue(String value) {
    String result = value;
    for (final pattern in _valuePatterns) {
      result = result.replaceAll(pattern, _redactedPlaceholder);
    }
    return result;
  }

  /// Provide a safe summary of auth-related data
  static Map<String, dynamic> summarizeAuthData(Map<String, dynamic>? data) {
    if (data == null) return {};
    return {
      'has_password': data.containsKey('password'),
      'has_email': data.containsKey('email'),
      'has_token': data.containsKey('token') ||
          data.containsKey('access_token') ||
          data.containsKey('refresh_token'),
      'fields_present': data.keys.toList(),
    };
  }
}

