import 'dart:collection';
import 'dart:convert';
import 'package:flutter/foundation.dart';

class AppLogger {
  static final AppLogger _instance = AppLogger._internal();
  factory AppLogger() => _instance;
  AppLogger._internal();

  LogLevel _minLevel = kDebugMode ? LogLevel.verbose : LogLevel.info;
  final List<LogSink> _sinks = [];
  final Queue<LogEntry> _recentLogs = Queue<LogEntry>();
  static const int _maxRecentLogs = 500;

  /// Configure the logger
  void configure({
    LogLevel? minLevel,
    List<LogSink>? sinks,
  }) {
    if (minLevel != null) _minLevel = minLevel;
    if (sinks != null) {
      _sinks.clear();
      _sinks.addAll(sinks);
    }
  }

  void addSink(LogSink sink) => _sinks.add(sink);

  void verbose(String tag, String message, {Map<String, dynamic>? metadata}) =>
      _log(LogLevel.verbose, tag, message, metadata: metadata);

  void debug(String tag, String message, {Map<String, dynamic>? metadata}) =>
      _log(LogLevel.debug, tag, message, metadata: metadata);

  void info(String tag, String message, {Map<String, dynamic>? metadata}) =>
      _log(LogLevel.info, tag, message, metadata: metadata);

  void warning(String tag, String message, {Map<String, dynamic>? metadata}) =>
      _log(LogLevel.warning, tag, message, metadata: metadata);

  void error(String tag, String message,
          {Map<String, dynamic>? metadata, StackTrace? stackTrace}) =>
      _log(LogLevel.error, tag, message,
          metadata: metadata, stackTrace: stackTrace?.toString());

  void fatal(String tag, String message,
          {Map<String, dynamic>? metadata, StackTrace? stackTrace}) =>
      _log(LogLevel.fatal, tag, message,
          metadata: metadata, stackTrace: stackTrace?.toString());

  void _log(LogLevel level, String tag, String message,
      {Map<String, dynamic>? metadata, String? stackTrace}) {
    if (level.index < _minLevel.index) return;

    // Always redact metadata before logging
    final safeMetadata =
        metadata != null ? SensitiveDataRedactor.redactMap(metadata) : null;

    final entry = LogEntry(
      level: level,
      tag: tag,
      message: SensitiveDataRedactor.redactString(message),
      metadata: safeMetadata,
      stackTrace: stackTrace,
    );

    _recentLogs.addLast(entry);
    if (_recentLogs.length > _maxRecentLogs) {
      _recentLogs.removeFirst();
    }

    for (final sink in _sinks) {
      sink.write(entry);
    }
  }

  List<LogEntry> getRecentLogs({LogLevel? minLevel}) {
    if (minLevel == null) return _recentLogs.toList();
    return _recentLogs
        .where((entry) => entry.level.index >= minLevel.index)
        .toList();
  }

  void clearLogs() => _recentLogs.clear();
}

