}

// lib/logging/console_log_sink.dart
class ConsoleLogSink implements LogSink {
  @override
  void write(LogEntry entry) {
    final prefix = _levelPrefix(entry.level);
    final logMessage = '$prefix ${entry.toString()}';

    if (entry.level.index >= LogLevel.error.index) {
      // Use print for errors so they're always visible
      // ignore: avoid_print
      print(logMessage);
      if (entry.stackTrace != null) {
        // ignore: avoid_print
        print(entry.stackTrace);
      }
    } else {
      // debugPrint handles throttling and is safer for verbose output
      debugPrint(logMessage);
    }

    if (entry.metadata != null && entry.metadata!.isNotEmpty) {
      debugPrint('  metadata: ${const JsonEncoder.withIndent(null).convert(entry.metadata)}');
    }
  }

  String _levelPrefix(LogLevel level) {
    switch (level) {
      case LogLevel.verbose:
        return '💬';
      case LogLevel.debug:
        return '🐛';
      case LogLevel.info:
        return 'ℹ️';
      case LogLevel.warning:
        return '⚠️';
      case LogLevel.error:
        return '❌';
      case LogLevel.fatal:
        return '💀';
      case LogLevel.none:
        return '';
    }
  }
}

// lib/logging/file_log_sink.dart
import 'dart:io';
import 'package:path_provider/path_provider.dart';

class FileLogSink implements LogSink {
  File? _logFile;
  final LogLevel minLevel;

  FileLogSink({this.minLevel = LogLevel.info});

  Future<void> initialize() async {
    final dir = await getApplicationDocumentsDirectory();
    final logDir = Directory('${dir.path}/logs');
    if (!await logDir.exists()) {
      await logDir.create(recursive: true);
    }
    final date = DateTime.now().toIso8601String().split('T').first;
    _logFile = File('${logDir.path}/app_$date.log');
  }

  @override
  void write(LogEntry entry) {
    if (entry.level.index < minLevel.index) return;
    if (_logFile == null) return;

    try {
      final line = '${const JsonEncoder().convert(entry.toJson())}\n';
      _logFile!.writeAsStringSync(line, mode: FileMode.append);
    } catch (e) {
      debugPrint('Failed to write log to file: $e');
    }
  }

  Future<void> cleanup({int maxAgeDays = 7}) async {
    final dir = await getApplicationDocumentsDirectory();
    final logDir = Directory('${dir.path}/logs');
    if (!await logDir.exists()) return;

    final cutoff = DateTime.now().subtract(Duration(days: maxAgeDays));
    await for (final entity in logDir.list()) {
      if (entity is File) {
        final stat = await entity.stat();
        if (stat.modified.isBefore(cutoff)) {
          await entity.delete();
        }
      }
    }
  }
}

