import 'dart:async';
import 'dart:collection';
import 'dart:convert';
import 'package:http/http.dart' as http;

class RemoteLogSink implements LogSink {
  final String endpoint;
  final String? apiKey;
  final LogLevel minLevel;
  final Duration flushInterval;
  final int maxBatchSize;

  final Queue<LogEntry> _buffer = Queue<LogEntry>();
  Timer? _flushTimer;

  RemoteLogSink({
    required this.endpoint,
    this.apiKey,
    this.minLevel = LogLevel.warning,
    this.flushInterval = const Duration(seconds: 30),
    this.maxBatchSize = 50,
  }) {
    _flushTimer = Timer.periodic(flushInterval, (_) => flush());
  }

  @override
  void write(LogEntry entry) {
    if (entry.level.index < minLevel.index) return;
    _buffer.addLast(entry);
    if (_buffer.length >= maxBatchSize) {
      flush();
    }
  }

  Future<void> flush() async {
    if (_buffer.isEmpty) return;

    final batch = <LogEntry>[];
    while (_buffer.isNotEmpty && batch.length < maxBatchSize) {
      batch.add(_buffer.removeFirst());
    }

    try {
      final headers = <String, String>{
        'Content-Type': 'application/json',
        if (apiKey != null) 'X-API-Key': apiKey!,
      };

      await http.post(
        Uri.parse(endpoint),
        headers: headers,
        body: jsonEncode({
          'logs': batch.map((e) => e.toJson()).toList(),
        }),
      );
    } catch (e) {
      // Re-add failed entries to front of buffer (with limit)
      for (final entry in batch.reversed) {
        if (_buffer.length < maxBatchSize * 3) {
          _buffer.addFirst(entry);
        }
      }
      debugPrint('Failed to send logs to remote: $e');
    }
  }

  void dispose() {
    _flushTimer?.cancel();
    flush(); // Final flush
  }
}

